import React, { useState, useEffect, useRef } from 'react';
import './index.css';
import geminiService from './services/geminiService';

const ChatbotWidget = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      id: 1,
      type: 'bot',
      content: 'Hi! I\'m your electricity bill assistant. I can help you understand why your bill might be high and suggest ways to reduce it. What would you like to know?',
      timestamp: new Date()
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [apiStatus, setApiStatus] = useState(null);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  const generateBotResponse = (userMessage) => {
    const message = userMessage.toLowerCase();
    
    // High bill analysis
    if (message.includes('high bill') || message.includes('expensive') || message.includes('cost') || message.includes('reduce')) {
      return {
        type: 'bot',
        content: `I understand you're concerned about your high electricity bill. Here's a step-by-step approach to reduce it:

**🔍 Immediate Actions:**
1. **Check for phantom loads** - Unplug devices that aren't in use (chargers, TVs on standby, etc.)
2. **Adjust thermostat** - Set AC to 78°F (26°C) or higher, use fans to circulate air
3. **Switch to LED bulbs** - Replace all incandescent and CFL bulbs with LEDs (saves 80% energy)
4. **Use natural light** - Open curtains during day, turn off unnecessary lights

**🏠 Appliance Optimization:**
• **Refrigerator**: Clean coils monthly, check door seals, set temp to 37-40°F
• **Washing Machine**: Use cold water, full loads only, air dry when possible
• **Dishwasher**: Run only when full, use eco mode
• **Water Heater**: Lower to 120°F, insulate tank, use timer

**💡 Smart Upgrades:**
• Install smart thermostats (saves 10-15%)
• Use smart plugs for scheduling devices
• Consider energy-efficient appliances (look for ENERGY STAR rating)
• Install solar panels for long-term savings

Would you like me to elaborate on any of these suggestions?`,
        timestamp: new Date()
      };
    }

    // Solar panel queries
    if (message.includes('solar') || message.includes('panel') || message.includes('renewable')) {
      return {
        type: 'bot',
        content: `Great question about solar panels! Here's what you should know:

**☀️ Solar Panel Benefits:**
• **Immediate savings**: 20-50% reduction in electricity bills
• **Long-term investment**: Payback period typically 6-10 years
• **Tax incentives**: Federal tax credits up to 30% of installation cost
• **Property value**: Increases home value by 3-4%

**💰 Cost Considerations:**
• Average residential system: $15,000-$25,000 (before incentives)
• Monthly savings: $100-$300 depending on usage and location
• Financing options: Solar loans, leases, or power purchase agreements

**🔧 Installation Factors:**
• Roof condition and orientation (south-facing ideal)
• Local regulations and permits
• Net metering policies in your area
• System size based on your energy consumption

**⚡ Alternative Options:**
• Community solar programs (no roof installation needed)
• Solar water heaters (immediate hot water savings)
• Solar attic fans (reduce AC load)

Would you like help calculating potential savings for your home?`,
        timestamp: new Date()
      };
    }

    // LED lighting queries
    if (message.includes('led') || message.includes('light') || message.includes('bulb')) {
      return {
        type: 'bot',
        content: `LED lighting is one of the easiest ways to save energy! Here's the complete guide:

**💡 LED vs Traditional Bulbs:**
• **Energy savings**: 80-90% less electricity than incandescent
• **Lifespan**: 25,000-50,000 hours vs 1,000 hours for incandescent
• **Heat output**: 90% less heat, reducing AC load
• **Cost**: Higher upfront but saves $50-100 per bulb over lifetime

**🏠 Where to Replace:**
• **High-use areas**: Kitchen, living room, bathroom
• **Outdoor lighting**: Security lights, porch lights
• **Decorative lighting**: String lights, accent lighting
• **Garage/workshop**: High-brightness LED strips

**⚡ Smart Lighting Options:**
• **Smart bulbs**: Control via phone, scheduling, dimming
• **Motion sensors**: Automatic on/off for security and convenience
• **Dimmer switches**: Adjust brightness to save more energy
• **Color temperature**: Cool white for work, warm white for relaxation

**📊 Quick Savings Calculator:**
• Replace 10 incandescent bulbs (60W each) with LEDs (9W each)
• Daily savings: 5.1 kWh = $0.51/day = $186/year
• Bulb cost: $50 vs annual savings: $186

Ready to start your LED upgrade? I can help you prioritize which lights to replace first!`,
        timestamp: new Date()
      };
    }

    // Appliance efficiency queries
    if (message.includes('appliance') || message.includes('fridge') || message.includes('ac') || message.includes('washing') || message.includes('dishwasher')) {
      return {
        type: 'bot',
        content: `Let's optimize your appliances for maximum energy efficiency! Here's a comprehensive guide:

**❄️ Refrigerator (Biggest Energy Hog):**
• **Temperature settings**: 37-40°F (fridge), 0-5°F (freezer)
• **Maintenance**: Clean coils every 6 months, check door seals
• **Location**: Keep away from heat sources, ensure proper ventilation
• **Upgrade**: ENERGY STAR models use 15% less energy

**🌡️ Air Conditioning:**
• **Thermostat**: Set to 78°F (26°C) or higher, use programmable thermostat
• **Maintenance**: Clean/replace filters monthly, service annually
• **Insulation**: Seal windows, doors, and ducts
• **Smart upgrades**: Smart thermostats save 10-15% automatically

**🧺 Washing Machine:**
• **Water temperature**: Use cold water for most loads (saves 90% energy)
• **Load size**: Full loads only, use appropriate water level
• **Drying**: Air dry when possible, clean lint trap
• **Upgrade**: Front-loading machines use 50% less water

**🍽️ Dishwasher:**
• **Run full loads**: Only run when completely full
• **Eco mode**: Use energy-saving settings
• **Air dry**: Skip heat dry, let dishes air dry
• **Pre-rinse**: Skip pre-rinsing, modern dishwashers handle it

**🔧 General Maintenance Tips:**
• Clean appliance filters regularly
• Check for leaks and repair promptly
• Consider appliance timers for off-peak usage
• Look for ENERGY STAR ratings when replacing

Which appliance would you like to focus on optimizing first?`,
        timestamp: new Date()
      };
    }

    // Smart home queries
    if (message.includes('smart') || message.includes('automation') || message.includes('timer') || message.includes('plug')) {
      return {
        type: 'bot',
        content: `Smart home technology can significantly reduce your energy bills! Here's how to get started:

**🏠 Smart Thermostats:**
• **Nest, Ecobee, Honeywell**: Learn your schedule, auto-adjust
• **Savings**: 10-15% on heating/cooling costs
• **Features**: Remote control, geofencing, energy reports
• **Installation**: DIY-friendly, professional installation available

**🔌 Smart Plugs & Switches:**
• **Scheduling**: Turn off devices during peak hours
• **Monitoring**: Track energy usage of individual devices
• **Voice control**: Works with Alexa, Google Assistant
• **Cost**: $15-50 per plug, easy to install

**💡 Smart Lighting:**
• **Automation**: Lights off when you leave, on when you return
• **Dimming**: Adjust brightness based on time of day
• **Color control**: Set mood lighting, reduce eye strain
• **Integration**: Works with other smart devices

**📱 Energy Monitoring:**
• **Whole-home monitors**: Track total usage, identify spikes
• **Appliance-specific**: Monitor individual device consumption
• **Real-time alerts**: Get notified of unusual usage patterns
• **Cost tracking**: See exactly how much each device costs

**⚡ Quick Smart Home Setup:**
1. Start with smart thermostat (biggest impact)
2. Add smart plugs for high-consumption devices
3. Install smart light switches in frequently used rooms
4. Set up automation routines for maximum savings

**💰 Expected Savings:**
• Smart thermostat: $100-200/year
• Smart plugs: $50-100/year
• Smart lighting: $30-80/year
• Total potential savings: $180-380/year

Would you like help choosing specific smart devices for your home?`,
        timestamp: new Date()
      };
    }

    // General energy saving tips
    if (message.includes('tip') || message.includes('save') || message.includes('help') || message.includes('advice')) {
      return {
        type: 'bot',
        content: `Here are my top energy-saving tips to reduce your electricity bill:

**⚡ Quick Wins (Do Today):**
1. **Unplug phantom loads** - Chargers, TVs, computers on standby
2. **Use power strips** - Turn off multiple devices with one switch
3. **Adjust water heater** - Lower to 120°F, use timer
4. **Close curtains** - Keep heat out in summer, warmth in during winter
5. **Use ceiling fans** - Allows higher thermostat settings

**🏠 Weekly Habits:**
• **Laundry**: Full loads only, cold water, air dry
• **Dishwasher**: Full loads, eco mode, air dry
• **Cooking**: Use microwave/air fryer instead of oven when possible
• **Cleaning**: Vacuum fridge coils, clean AC filters

**📅 Monthly Maintenance:**
• **HVAC**: Clean/replace air filters
• **Refrigerator**: Clean coils, check door seals
• **Lighting**: Dust bulbs and fixtures
• **Electronics**: Update software for efficiency

**🔧 Seasonal Adjustments:**
• **Summer**: Close blinds, use fans, set AC to 78°F+
• **Winter**: Open blinds for sunlight, seal drafts, lower heat
• **Spring/Fall**: Open windows, use natural ventilation

**💡 Long-term Investments:**
• **LED bulbs**: Replace all incandescent bulbs
• **Smart thermostat**: Automate temperature control
• **Energy audit**: Professional assessment of your home
• **Appliance upgrade**: Replace old, inefficient appliances

**📊 Track Your Progress:**
• Monitor monthly bills
• Use energy monitoring apps
• Set monthly reduction goals
• Celebrate savings milestones

What specific area would you like to focus on first?`,
        timestamp: new Date()
      };
    }

    // Default response
    return {
      type: 'bot',
      content: `I'm here to help with your electricity bill questions! I can assist with:

• **High bill analysis** - Understanding why your bill is expensive
• **Energy-saving tips** - Practical ways to reduce consumption
• **Appliance optimization** - Making your devices more efficient
• **Smart home solutions** - Technology to automate savings
• **Solar panel advice** - Renewable energy options
• **LED lighting** - Upgrading to efficient lighting
• **Maintenance schedules** - Keeping appliances running efficiently

Just ask me about any of these topics, or tell me what's concerning you about your electricity bill!`,
      timestamp: new Date()
    };
  };

  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMessage = {
      id: Date.now(),
      type: 'user',
      content: inputValue,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    // Simulate typing delay
    setTimeout(() => {
      const botResponse = generateBotResponse(inputValue);
      setMessages(prev => [...prev, { ...botResponse, id: Date.now() + 1 }]);
      setIsTyping(false);
    }, 1000 + Math.random() * 1000);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const toggleChatbot = () => {
    setIsOpen(!isOpen);
  };

  return (
    <>
      {/* Floating Button */}
      <button
        onClick={toggleChatbot}
        className={`fixed bottom-6 right-6 z-50 w-14 h-14 bg-electric-blue text-white rounded-full shadow-lg floating-button transition-all duration-300 hover:scale-110 ${
          isOpen ? 'hidden' : 'block'
        }`}
        aria-label="Open electricity bill chatbot"
      >
        <svg
          className="w-6 h-6 mx-auto"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={2}
            d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"
          />
        </svg>
      </button>

      {/* Chatbot Widget */}
      <div
        className={`fixed bottom-6 right-6 z-50 chatbot-widget ${
          isOpen ? 'block' : 'hidden'
        }`}
      >
        <div className="bg-white rounded-2xl shadow-2xl w-80 sm:w-96 h-96 sm:h-[500px] flex flex-col border border-gray-200">
          {/* Header */}
          <div className="bg-gradient-to-r from-electric-blue to-energy-green text-white p-4 rounded-t-2xl flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-white bg-opacity-20 rounded-full flex items-center justify-center">
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                </svg>
              </div>
              <div>
                <h3 className="font-semibold text-sm">Electricity Assistant</h3>
                <p className="text-xs opacity-90">Online now</p>
              </div>
            </div>
            <button
              onClick={toggleChatbot}
              className="text-white hover:text-gray-200 transition-colors"
              aria-label="Close chatbot"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto chat-scroll p-4 space-y-4">
            {messages.map((message) => (
              <div
                key={message.id}
                className={`chat-message flex ${
                  message.type === 'user' ? 'justify-end' : 'justify-start'
                }`}
              >
                <div
                  className={`max-w-[80%] p-3 rounded-2xl ${
                    message.type === 'user'
                      ? 'bg-electric-blue text-white'
                      : 'bg-gray-100 text-gray-800'
                  }`}
                >
                  <div className="text-sm whitespace-pre-line">{message.content}</div>
                  <div
                    className={`text-xs mt-1 ${
                      message.type === 'user' ? 'text-blue-100' : 'text-gray-500'
                    }`}
                  >
                    {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
            ))}
            
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-gray-100 text-gray-800 p-3 rounded-2xl">
                  <div className="flex space-x-1">
                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                  </div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <div className="p-4 border-t border-gray-200">
            <div className="flex space-x-2">
              <input
                ref={inputRef}
                type="text"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder="Ask about your electricity bill..."
                className="flex-1 px-4 py-2 border border-gray-300 rounded-full focus:outline-none focus:ring-2 focus:ring-electric-blue focus:border-transparent text-sm"
              />
              <button
                onClick={handleSendMessage}
                disabled={!inputValue.trim()}
                className="bg-electric-blue text-white p-2 rounded-full hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                aria-label="Send message"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                </svg>
              </button>
            </div>
            <p className="text-xs text-gray-500 mt-2 text-center">
              Press Enter to send • Shift+Enter for new line
            </p>
          </div>
        </div>
      </div>
    </>
  );
};

export default ChatbotWidget;
